const smokeParticles = [];
const smokeMaterial = new THREE.MeshPhongMaterial({ 
  color: 0x888888, 
  transparent: true, 
  opacity: 0.5 
});
const smokeGeom = new THREE.SphereGeometry(0.1, 8, 8);
function createSmoke() {
  const smoke = new THREE.Mesh(smokeGeom, smokeMaterial);
  smoke.position.set(0.7, 0.7, 0);
  scene.add(smoke);
  smokeParticles.push(smoke);
}